worked_example.final_code:
import org.junit.jupiter.api.*;
import org.junit.jupiter.params.*;
import org.junit.jupiter.params.provider.*;
import static org.junit.jupiter.api.Assertions.*;
import java.util.stream.Stream;

record Order(String productName, int qty, double price, String discountTier) {}
class OrderValidator {
    void validate(Order o) {
        if (o == null) throw new NullPointerException("Order cannot be null");
        if (o.productName() == null || o.productName().isBlank())
            throw new IllegalArgumentException("Product name blank");
        if (o.qty() < 1 || o.qty() > 999)
            throw new IllegalArgumentException("Qty out of range: " + o.qty());
        if (o.price() <= 0 || o.price() >= 1_000_000)
            throw new IllegalArgumentException("Invalid price: " + o.price());
        if (o.qty() >= 10 && (o.discountTier() == null || o.discountTier().isBlank()))
            throw new IllegalArgumentException("Discount tier required for qty >= 10");
    }
    boolean isValid(Order o) {
        try { validate(o); return true; } catch (Exception e) { return false; }
    }
}

class OrderValidatorTest {
    OrderValidator validator = new OrderValidator();

    @ParameterizedTest @CsvSource({
        "Mouse,     1,  799,   '',  true",
        "Keyboard, 10, 1999, BULK, true",
        "'',        1,  799,   '',  false",
        "Mouse,     0,  799,   '',  false",
        "Mouse,  1000,  799,   '',  false",
        "Mouse,     1,    0,   '',  false",
        "Mouse,    10,  799,   '',  false"
    })
    void isValid_csvCases(String name, int qty, double price,
                           String tier, boolean expected) {
        Order o = new Order(name, qty, price, tier.isBlank() ? null : tier);
        assertEquals(expected, validator.isValid(o));
    }

    @ParameterizedTest @CsvSource({"0,false","1,true","2,true","998,true","999,true","1000,false"})
    void validate_qtyBoundary(int qty, boolean expected) {
        Order o = new Order("Mouse", qty, 799, qty >= 10 ? "BULK" : null);
        assertEquals(expected, validator.isValid(o));
    }

    @ParameterizedTest @NullAndEmptySource
    void validate_nullOrEmptyProductName_fails(String name) {
        assertFalse(validator.isValid(new Order(name, 1, 799, null)));
    }

    @Test
    void validate_nullOrder_throwsNPE() {
        assertThrows(NullPointerException.class, () -> validator.validate(null));
    }
}
